={{ (() => {
  const status = $('Data Handler1').item.json.status;
  const descricao = $('Data Handler1').item.json.descricao || '';
  const purchaseDescription = $('Data Handler1').item.json.purchase_description || '';
  const purchaseDate = $('Data Handler1').item.json.purchase_date || '';

  // Formatar data: DD-MM às HHhrs
  let formattedDate = '';
  if (purchaseDate) {
    try {
      const date = new Date(purchaseDate);
      const day = String(date.getDate()).padStart(2, '0');
      const month = String(date.getMonth() + 1).padStart(2, '0');
      const hours = String(date.getHours()).padStart(2, '0');
      formattedDate = `${day}-${month} às ${hours}hrs`;
    } catch (e) {
      formattedDate = '';
    }
  }

  // Montar mensagem de status
  let statusMessage = '';
  if (status === 'aprovar') {
    statusMessage = '✅ Aprovado';
  } else if (status === 'rejeitar') {
    statusMessage = '❌ Rejeitado';
  } else {
    statusMessage = '⚠️ Solicitação de Esclarecimento';
  }

  // Montar mensagem completa
  let fullMessage = statusMessage;

  // Adicionar informações da compra se disponíveis
  if (formattedDate && purchaseDescription) {
    fullMessage += '\n\nRegistro feito em ' + formattedDate + ' "' + purchaseDescription + '"';
  } else if (formattedDate) {
    fullMessage += '\n\nRegistro feito em ' + formattedDate;
  } else if (purchaseDescription) {
    fullMessage += '\n\n"' + purchaseDescription + '"';
  }

  // Adicionar descrição adicional se houver
  if (descricao && descricao.trim() !== '') {
    fullMessage += '\n\n' + descricao;
  }

  return {
    number: $('Data Handler1').item.json.telefone.replace(/[^0-9]/g, ''),
    text: fullMessage,
    options: { delay: 2000, presence: "composing" }
  };
})() }}
